<div class="card card-rounded"><div class="card-body"><form method="post" action="correo-enviar.php" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="hilo_id" value="<?=$hilo?>"><div class="mb-3"><label class="form-label">Destinatario</label><select class="form-select" name="destinatario_id" required><option value="">Selecciona un contacto autorizado</option><?php foreach($contactos as$c):?><option value="<?=$c['id']?>" <?=$destino===(int)$c['id']?'selected':''?>><?=atenea_e(trim($c['nombre'].' '.$c['apellido']).' · '.$c['correo'].' · '.etiquetaRolComunicacion($c['rol']))?></option><?php endforeach;?></select></div><div class="mb-3"><label class="form-label">Asunto</label><input class="form-control" name="asunto" maxlength="190" value="<?=atenea_e($asunto!==''&&!str_starts_with($asunto,'Re:')?'Re: '.$asunto:$asunto)?>" required></div><div class="mb-3"><label class="form-label">Mensaje</label><textarea class="form-control" name="mensaje" maxlength="20000" rows="9" required></textarea></div><div class="mb-3"><label class="form-label">Adjunto opcional (PDF, Office, imagen o TXT; máximo 10 MB)</label><input class="form-control" type="file" name="adjunto" accept=".pdf,.doc,.docx,.jpg,.jpeg,.png,.webp,.txt"></div><button class="btn btn-primary">Enviar correo real</button></form></div></div><?php comunicacionPie();
